import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o as l,c as d,a as i,d as t,b as e,e as c}from"./app-46d6f74d.js";const h={},p=c('<h2 id="打粉-df" tabindex="-1"><a class="header-anchor" href="#打粉-df" aria-hidden="true">#</a> 打粉／df</h2><p><strong>「打粉」</strong> 是苏打绿歌迷的自称，据传是「苏打粉」（也是一种化学品）的简称。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/wiki/dafen.jpg" alt="生活处处有打粉" width="300" tabindex="0" loading="lazy"><figcaption>生活处处有打粉</figcaption></figure><h2 id="打粉老师-dfls" tabindex="-1"><a class="header-anchor" href="#打粉老师-dfls" aria-hidden="true">#</a> 打粉老师／dfls</h2><p>据称是有一次吴青峰发了一条微博询问一个数学题，粉丝给出了解答。又因娱乐圈兴起了称呼对方为老师，以显示自己的尊重，因此粉丝群体们兴起了 <strong>「打粉老师」</strong>（简称 dfls）这个称号。</p><p>另一个版本是，吴青峰说他大学的遗憾就是没有谈一场师生恋，所以粉丝们就自称为「打粉老师」。</p><p>其实是因为苏打绿的粉丝遍布各行各业，大家都很厉害，所以才会有这个称号～</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/wiki/dfls.jpg" alt="" width="300" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="浮萍-池堂" tabindex="-1"><a class="header-anchor" href="#浮萍-池堂" aria-hidden="true">#</a> 浮萍／池堂</h2><p><strong>「浮萍」</strong> 是鱼丁糸粉丝的官方名称。2020 年，苏打绿以「鱼丁糸」身份回归时，为歌迷们取好了新的代号为「浮萍」，而歌迷会叫作「池堂」。</p><div class="hint-container tip"><p class="hint-container-title">阿龚在鱼丁糸出道演唱会「Follow Me」上的介绍</p><p>全 <strong>池堂</strong> 里面的 <strong>浮萍</strong> 们，你们好，我们是——鱼丁糸！</p></div><h2 id="吹峰机" tabindex="-1"><a class="header-anchor" href="#吹峰机" aria-hidden="true">#</a> 吹峰机</h2><p><strong>「吹峰机」</strong> 是吴青峰粉丝的名称。起因是在 2019 年初，粉丝在〈起风了〉歌曲中评论：</p><blockquote><p>我是一个没有感情的吹峰机！！！</p></blockquote><p>同年春节期间，王源晒出了最近的歌单，包含青峰在《歌手》节目中唱的〈我们〉，青峰本人评论表示开心。然后王源用了「吹峰机」这个梗，青峰表示不可思议。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/wiki/chuifengji.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="善心人士以及其他称呼" tabindex="-1"><a class="header-anchor" href="#善心人士以及其他称呼" aria-hidden="true">#</a> 善心人士以及其他称呼</h2><p><strong>「善心人士」</strong> 是吴青峰为自己的粉丝取的名字。起因是在 2020 年 5 月 18 日，吴青峰发微博与大家每周一聊，随后有粉丝在微博下留言询求青峰给粉丝统一一下称呼，随后青峰回应提问并将粉丝取名为「善心人士」。</p><figure><img src="https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/wiki/shanxinrenshi.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>科普一下上图中其他粉丝称呼来源：</p>',20),g=i("p",null,[i("strong",null,"啵啵鱼"),e("：青峰在一次采访中，称粉丝像公园里的鱼，给了饵料会“啵啵啵”。")],-1),u=i("p",null,"2019 年 12 月 30 日，青峰在莫文蔚演唱会担任嘉宾后，在微博中说：“啵啵啵，我也當過池子裡的魚呢，哈哈。”将自己早年追星经历（参加莫文蔚演唱会）也比喻成「啵啵鱼」。",-1),f=i("strong",null,"啵啵鲨",-1),_={href:"https://weibo.com/1822796164/IoTLF2nuQ",target:"_blank",rel:"noopener noreferrer"},b=i("li",null,[i("p",null,[i("strong",null,"倾听者"),e("、"),i("strong",null,"聆听者"),e("：青峰在 2019 年发表了〈歌颂者〉，歌词中说“我想我很值得，当一个歌颂者”，之后青峰在微博简介中称自己是「歌颂者」。因此粉丝们自称为「倾听者」或「聆听者」。")])],-1),k=i("li",null,[i("p",null,[i("strong",null,"听众"),e("：青峰希望粉丝与他是朋友的关系，因此大部分情况下称粉丝为「听众」或「观众」，偶尔也说过「歌迷」。")])],-1);function m(x,j){const a=n("BiliBili"),o=n("ExternalLinkIcon"),s=n("VideoPlayer");return l(),d("div",null,[p,i("ul",null,[i("li",null,[g,t(a,{bvid:"BV1n7411h7Vk",width:"75%"}),u]),i("li",null,[i("p",null,[f,e("：2020 年 1 月 10 日，吴青峰「太空备忘记」演唱会深圳场中，偷拍的观众很多，青峰当晚很不开心，少唱了一首歌并在微博发了 "),i("a",_,[e("长文"),t(o)]),e("。1 月 11 日的演唱会开场前观众入座时，粉丝们自发提醒大家不要拍照。青峰在后台听见了，并在演唱会 talking 时讲到大家母爱爆棚，赞赏大家是彪悍的「啵啵鲨」，说感觉要是有人偷拍会不会被大家丢出去。")]),t(s,{src:"https://cdn.jsdelivr.net/gh/kaluojushi/sodaguide@picbed/wiki/bobosha.mp4",width:"75%"})]),b,k])])}const B=r(h,[["render",m],["__file","fans.html.vue"]]);export{B as default};
